package com.cognizant.resource.config;import javax.crypto.SecretKey;import javax.crypto.spec.SecretKeySpec;import org.springframework.beans.factory.annotation.Value;import org.springframework.context.annotation.*;import org.springframework.security.config.Customizer;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.oauth2.jose.jws.MacAlgorithm;import org.springframework.security.oauth2.jwt.*;import org.springframework.security.web.SecurityFilterChain;@Configuration public class ResourceServerConfig{@Bean JwtDecoder decoder(@Value("${security.jwt.secret}")String s){SecretKey k=new SecretKeySpec(s.getBytes(java.nio.charset.StandardCharsets.UTF_8),"HmacSHA256");return NimbusJwtDecoder.withSecretKey(k).macAlgorithm(MacAlgorithm.HS256).build();}@Bean SecurityFilterChain chain(HttpSecurity h)throws Exception{return h.authorizeHttpRequests(a->a.requestMatchers("/actuator/health").permitAll().anyRequest().authenticated()).oauth2ResourceServer(o->o.jwt(Customizer.withDefaults())).build();}}
